// components/LeftSidebar.js
// Sidebar with draggable node components, auto-generated from nodeRegistry.
// Grouped by category with search filtering.

import { useState, useMemo } from 'react';
import { getSidebarItems } from '../nodes/nodeRegistry';
import { Search, Blocks } from 'lucide-react';

export const LeftSidebar = () => {
  const [search, setSearch] = useState('');
  const categories = useMemo(() => getSidebarItems(), []);

  const filtered = useMemo(() => {
    if (!search.trim()) return categories;
    const q = search.toLowerCase();
    return categories
      .map((cat) => ({
        ...cat,
        items: cat.items.filter((n) => n.label.toLowerCase().includes(q)),
      }))
      .filter((cat) => cat.items.length > 0);
  }, [search, categories]);

  return (
    <div
      style={{
        width: '260px',
        background: 'var(--bg-surface)',
        borderRight: '1px solid var(--border-subtle)',
        display: 'flex',
        flexDirection: 'column',
        height: 'calc(100vh - 56px)',
        zIndex: 10,
      }}
    >
      {/* Search */}
      <div style={{ padding: '16px 14px 8px' }}>
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            background: 'var(--bg-app)',
            border: '1px solid var(--border-subtle)',
            borderRadius: '8px',
            padding: '8px 12px',
            transition: 'border-color 0.15s',
          }}
        >
          <Search size={14} color="var(--text-tertiary)" />
          <input
            type="text"
            placeholder="Search nodes..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{
              flex: 1,
              background: 'transparent',
              border: 'none',
              outline: 'none',
              color: 'var(--text-primary)',
              fontSize: '12px',
              fontFamily: 'inherit',
            }}
          />
        </div>
      </div>

      {/* Node list by category */}
      <div style={{ flex: 1, overflowY: 'auto', padding: '8px 14px 16px' }}>
        {filtered.map((cat) => (
          <div key={cat.category} style={{ marginBottom: '16px' }}>
            <div
              style={{
                fontSize: '10px',
                fontWeight: 600,
                color: 'var(--text-tertiary)',
                textTransform: 'uppercase',
                letterSpacing: '0.08em',
                marginBottom: '8px',
                padding: '0 2px',
              }}
            >
              {cat.label}
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
              {cat.items.map((n) => {
                const IconComponent = n.icon;
                return (
                  <div
                    key={n.type}
                    draggable
                    onDragStart={(e) => {
                      e.dataTransfer.setData(
                        'application/reactflow',
                        JSON.stringify({ nodeType: n.type })
                      );
                      e.dataTransfer.effectAllowed = 'move';
                    }}
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: '10px',
                      padding: '9px 12px',
                      background: 'transparent',
                      border: '1px solid transparent',
                      borderRadius: 'var(--radius-sm)',
                      cursor: 'grab',
                      color: 'var(--text-secondary)',
                      transition: 'all 0.15s ease',
                      userSelect: 'none',
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.background = 'rgba(255,255,255,0.03)';
                      e.currentTarget.style.borderColor = 'var(--border-subtle)';
                      e.currentTarget.style.color = 'var(--text-primary)';
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.background = 'transparent';
                      e.currentTarget.style.borderColor = 'transparent';
                      e.currentTarget.style.color = 'var(--text-secondary)';
                    }}
                  >
                    <div
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        width: 26,
                        height: 26,
                        borderRadius: '6px',
                        background: `color-mix(in srgb, ${n.color} 10%, transparent)`,
                        color: n.color,
                        flexShrink: 0,
                      }}
                    >
                      <IconComponent size={14} />
                    </div>
                    <span style={{ fontSize: '13px', fontWeight: 500 }}>{n.label}</span>
                  </div>
                );
              })}
            </div>
          </div>
        ))}

        {filtered.length === 0 && (
          <div
            style={{
              textAlign: 'center',
              color: 'var(--text-tertiary)',
              fontSize: '12px',
              padding: '24px 0',
            }}
          >
            No nodes match "{search}"
          </div>
        )}
      </div>

      {/* Footer */}
      <div style={{ padding: '14px 16px', borderTop: '1px solid var(--border-subtle)' }}>
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: '10px',
            color: 'var(--text-tertiary)',
          }}
        >
          <Blocks size={14} />
          <span style={{ fontSize: '11px', fontWeight: 500 }}>VectorShift Pipeline</span>
        </div>
      </div>
    </div>
  );
};
